// Função volume -> embalagem (COM NORMALIZAÇÃO CORRIGIDA)
function volumeParaEmbalagemCorreta(volume) {
  // 🔥 CORREÇÃO AQUI: remove TODOS os espaços em branco
  const v = (volume || '').toLowerCase().replace(/\s+/g, '').replace(',', '.');

  // REGRA 1: Litro
  if (['0.9', '0,9', '900ml', '0.9l'].includes(v)) {
    return 'LITRO';
  }

  // REGRA 2: Galão
  if (['3.6', '3,6', '3.6l', '3,6l'].includes(v)) {
    return 'GALÃO';
  }

  // REGRA 3: Lata
  if (['18', '18l', '18.0', '16', '16l', '16.0', '18.0l', '16.0l'].includes(v)) {
    return 'LATA';
  }

  return ''; // Se o volume não for nenhum dos padrões, não retorna nada.
}

// Pega o volume e acabamento que o cliente pediu
const volumePedido = items[0].json.volume;
const acabamentoEsperado = (items[0].json.acabamento || '').toLowerCase().trim();

// Usa a função CORRETA para definir qual a ÚNICA embalagem esperada
const embalagemEsperada = volumeParaEmbalagemCorreta(volumePedido);

// Filtra a lista de produtos, ignorando os dados errados da API
const resultado = items.filter(item => {
  // A embalagem do item da API (ex: "LATA") deve ser EXATAMENTE IGUAL
  // à embalagem correta para o volume (ex: "LATA" para 18L).
  const matchEmbalagem = item.json.embalagemSimplificada === embalagemEsperada;

  // A lógica de acabamento continua a mesma
  const matchAcabamento = acabamentoEsperado
    ? (item.json.acabamento || '').toLowerCase().includes(acabamentoEsperado)
    : true;

  return matchEmbalagem && matchAcabamento;
});

// Se, após os filtros, a lista ficar vazia, retorna um erro.
if (resultado.length === 0) {
  throw new Error('Nenhum produto encontrado para esse acabamento/embalagem.');
}

// Prepara os dados limpos para o próximo nó do fluxo
const dadosCliente = resultado.map(item => ({
  json: {
    codigoEmpresa: item.json.codigoEmpresa,
    sigla: item.json.sigla,
    cor: item.json.cor,
    volume: item.json.volume,
    rgb: item.json.rgb,
    codigoCor: item.json.codigoCor,
    acabamento: item.json.acabamento,
    embalagem: item.json.embalagemSimplificada,
    ordemEmbalagem: item.json.ordemEmbalagemSimplificada,
  }
}));

return dadosCliente;

// === 1) Referência e normalização ===
const ref = items[0]?.json || {};
const acabamentoCliente = ref.acabamento || '';

function normaliza(txt) {
  return (txt || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim();
}

// Equivalências (bidirecional simples)
const equivalencias = {
  // acetinado / sedoso
  acetinado: ['acetinado', 'acetinada', 'seda', 'sedoso'],
  acetinada: ['acetinado', 'acetinada', 'seda', 'sedoso'],
  seda:      ['acetinado', 'acetinada', 'seda', 'sedoso'],
  sedoso:    ['acetinado', 'acetinada', 'seda', 'sedoso'],

  // fosco
  fosco: ['fosco', 'matte'],
  matte: ['fosco', 'matte'],

  // brilhante
  brilhante: ['brilho', 'brilhante'],
  brilho:    ['brilho', 'brilhante'],
  semibrilho: ['diamante'],

  // clássica
  classica:    ['classica', 'tradicional'],
  tradicional: ['classica', 'tradicional'],
};

const acbClienteNorm = normaliza(acabamentoCliente);
const palavrasAceitas = acbClienteNorm
  ? (equivalencias[acbClienteNorm] || [acbClienteNorm])
  : null; // null => não filtra por acabamento quando cliente não informou

// === 2) Filtra itens válidos (descarta item 0 e quem não tem chaveCitel) ===
let candidatos = items.slice(1).filter(i => !!i?.json?.chaveCitel);

// === 3) Aplica filtro por acabamento (somente se cliente informou algo) ===
if (palavrasAceitas) {
  candidatos = candidatos.filter(i => {
    const acbItem = normaliza(i.json.acabamento);
    if (!acbItem) return false;
    return palavrasAceitas.some(word =>
      acbItem.includes(word) || word.includes(acbItem)
    );
  });
}

// === 4) Deduplica por chaveCitel (evita POST duplicado) ===
const vistos = new Set();
candidatos = candidatos.filter(i => {
  const k = String(i.json.chaveCitel);
  if (vistos.has(k)) return false;
  vistos.add(k);
  return true;
});

// === 5) Monta saída padronizada (hashesMd5 sempre preenchido) ===
return candidatos.map(i => ({
  json: {
    codigoCliente: "000001",
    codigoEmpresa: ref.codigoEmpresa,
    sigla: ref.sigla,
    idPro: ref.sigla,
    rgb: i.json.rgb,
    hashesMd5: [String(i.json.chaveCitel)],
    cor: i.json.cor,
    acabamento: i.json.acabamento,
    embalagem: i.json.embalagem,
    codigoCor: i.json.codigoCor ?? '',
  }
}));

// saída: [{ json: { mensagem } }]

// === UTILS (funções auxiliares) ===
const up = s => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toUpperCase().trim();

function volumeByEmbalagem(e = '') {
  const v = up(e);
  if (v.includes('LATA')) return '18 L';
  if (v.includes('GALAO')) return '3,6 L';
  if (v.includes('LITRO') || v === 'L') return '0,9 L';
  return '';
}

function embalagemEsperada(volume) {
  const v = String(volume || '').replace(',', '.').replace(/\s+/g,'').toUpperCase();
  if (v.startsWith('18'))  return 'LATA';
  if (v.startsWith('3.6')) return 'GALAO';
  if (v.startsWith('0.9') || v.includes('900ML')) return 'LITRO';
  return '';
}
// === FIM UTILS ===


// 1) Pega os metadados do pedido do cliente (o último item)
const meta = items[items.length - 1]?.json || {};
const SIGLA  = up(meta.sigla);
const SUPERF = up(meta.superficie || meta['superfície']);
const ACABPD = up(meta.acabamento || meta.acabamentoPedido);
const VOLRAW = meta.volume || '';
const CODCOR = meta.codigoCor || '';

// 2) Define a sub-categoria (se é premium fosco, acetinado, etc.)
function catKey(acabPed) {
  if (acabPed.includes('FOSCO') && acabPed.includes('LAV')) return 'premium_fosco_lavavel';
  if (acabPed.includes('FOSCO')) return 'premium_fosco';
  if (acabPed.includes('ACET')) return 'premium_acetinado';
  if (acabPed.includes('SEMI') || acabPed.includes('BRILHO')) return 'premium_semibrilho';
  return 'premium_fosco';
}
const CAT = catKey(ACABPD);

// 3) Separa descrições e preços, depois combina por hash
const descs  = items.filter(i => Array.isArray(i.json?.hashesMd5)).map(i => i.json);
const prices = items.filter(i => typeof i.json?.hashMd5 === 'string').map(i => i.json);
const priceByHash = Object.fromEntries(prices.map(p => [p.hashMd5, p]));

let produtos = descs.map(d => {
  const h = d.hashesMd5?.[0];
  const p = priceByHash[h];
  if (!p) return null;
  return {
    sigla: d.sigla,
    cor: d.cor,
    acabamento: d.acabamento,
    embalagem: d.embalagem,
    volume: d.volume,
    preco: Number(p.preco1 || 0),
    hash: h,
  };
}).filter(Boolean);

// 4) Filtra por embalagem coerente com o volume
const embOK = embalagemEsperada(VOLRAW);
if (embOK) produtos = produtos.filter(p => up(p.embalagem) === embOK);

// ✅ NOVA REGRA: Sempre prioriza TMC INSPIRA se existir nos candidatos com preço > 0
const tmcInspira = produtos.find(p => {
  const acab = up(p.acabamento);
  return acab.includes('TMC INSPIRA') && p.preco > 0;
});

if (tmcInspira) {
  // Se encontrou TMC INSPIRA, retorna ele direto
  const volStr = volumeByEmbalagem(tmcInspira.embalagem) || tmcInspira.volume || VOLRAW || '';
  const desc = `${tmcInspira.sigla} ${tmcInspira.cor} ${tmcInspira.acabamento} ${tmcInspira.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
  const precoBRL = tmcInspira.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const mensagem = `• ${desc} por ${precoBRL}\n\nPosso seguir com esse item?`;

  return [{ json: { mensagem } }];
}

// 5) Se não encontrou TMC INSPIRA, segue com as regras normais de prioridade
const regras = {
  premium_fosco: {
    SUV: ['TOQUE FOSCO COMPLETO'], 
    SHW: ['METALATEX ACRILICO FOSCO', 'NOVO METALATEX ACRILICO FOSCO'],
    CIM: ['DECORA MATTE FO', '3 EM 1 FOSCO', 'CORAL MASTER FOSCO'],
    TMC: ['INSPIRA FOSCO', 'TMC INSPIRA FOSCO'],
  },
  premium_fosco_lavavel: {
    SUV: ['SEMPRE LIMPO'],
    CIM: ['SUPER LAVAVEL'],
  },
  premium_acetinado: {
    SUV: ['TOQUE DE SEDA', 'TOQUE SEDA'],
    SHW: ['METALATEX ELASTIC SEMIACETINADO'],
    CIM: ['DECORA SEDA'],
  },
  premium_semibrilho: {
    SUV: ['TOQUE BRILHO'],
    SHW: ['METALATEX ACRILICO SEMIBRILHO'],
    CIM: ['DECORA DIAMANTE'],
  },
};

// 6) Função que pula produtos com preço zero
function pickByPriority(sigla, cat, listaProdutos) {
  const arr = (regras[cat] || {})[sigla] || [];
  if (!arr.length) return null;

  for (const alvo of arr) {
    const A = up(alvo);

    const found = listaProdutos.find(p => {
        const acabamentoProduto = up(p.acabamento);
        return acabamentoProduto.includes(A) && p.preco > 0;
    });

    if (found) return found;
  }
  return null;
}

const escolhido = pickByPriority(SIGLA, CAT, produtos);

// 7) Monta a resposta final
if (!escolhido) {
  return [{ json: { mensagem: `Não encontrei item premium compatível (Linha/Acabamento: ${ACABPD}, Marca: ${SIGLA}) para o volume ${VOLRAW}. Quer tentar outro produto?` } }];
}

const volStr = volumeByEmbalagem(escolhido.embalagem) || escolhido.volume || VOLRAW || '';
const desc = `${escolhido.sigla} ${escolhido.cor} ${escolhido.acabamento} ${escolhido.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
const precoBRL = escolhido.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const mensagem = `• ${desc} por ${precoBRL}\n\nPosso seguir com esse item?`;

return [{ json: { mensagem } }];

