// utils
const up = s => String(s || '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
  .toUpperCase().trim();

function volumeByEmbalagem(e = '') {
  const v = up(e);
  if (v.includes('LATA')) return '18 L';
  if (v.includes('GALAO')) return '3,6 L';
  if (v.includes('LITRO') || v === 'L') return '0,9 L';
  return '';
}

function embalagemEsperada(volume) {
  const v = String(volume || '').replace(',', '.').replace(/\s+/g,'').toUpperCase();
  if (v.startsWith('18'))  return 'LATA';
  if (v.startsWith('3.6')) return 'GALAO';   // ✅ sem acento, bate com up()
  if (v.startsWith('0.9') || v.includes('900ML')) return 'LITRO';
  return '';
}

// 1) pedido vem no último item
const meta = items[items.length - 1]?.json || {};
const SIGLA  = up(meta.sigla);
const SUPERF = up(meta.superficie || meta['superfície']);
const ACABPD = up(meta.acabamento || meta.acabamentoPedido);
const VOLRAW = meta.volume || '';
const CODCOR = meta.codigoCor || ''; // tintométrico = premium sempre

// 2) categoria agora sempre premium, subdivide por acabamento
function catKey(acabPed) {
  if (acabPed.includes('FOSCO') && acabPed.includes('LAV')) return 'premium_fosco_lavavel';
  if (acabPed.includes('FOSCO')) return 'premium_fosco';
  if (acabPed.includes('ACET')) return 'premium_acetinado';
  if (acabPed.includes('SEMI') || acabPed.includes('BRILHO')) return 'premium_semibrilho';
  return 'premium_fosco';
}
const CAT = catKey(ACABPD);

// 3) separa descrições e preços, depois combina por hash
const descs  = items.filter(i => Array.isArray(i.json?.hashesMd5)).map(i => i.json);
const prices = items.filter(i => typeof i.json?.hashMd5 === 'string').map(i => i.json);
const priceByHash = Object.fromEntries(prices.map(p => [p.hashMd5, p]));

let produtos = descs.map(d => {
  const h = d.hashesMd5?.[0];
  const p = priceByHash[h];
  if (!p) return null;
  return {
    sigla: d.sigla,
    cor: d.cor,
    acabamento: d.acabamento,
    embalagem: d.embalagem,
    volume: d.volume,
    preco: Number(p.preco1 || 0),
    hash: h,
  };
}).filter(Boolean).filter(x => x.preco > 0);

// 4) filtra por embalagem coerente com o volume
const embOK = embalagemEsperada(VOLRAW);
if (embOK) produtos = produtos.filter(p => up(p.embalagem) === embOK);

// 5) regras só premium
const regras = {
  premium_fosco: {
    SHW: ['METALATEX ACRILICO FOSCO','NOVO METALATEX ACRILICO FOSCO'],
    SUV: ['TOQUE FOSCO COMPLETO'],
    CIM: ['DECORA MATTE FO (ANTIGO) - 3.2 L'],
    TMC: ['INSPIRA FOSCO','TMC INSPIRA FOSCO'],
  },
  premium_fosco_lavavel: {
    SUV: ['SEMPRE LIMPO'],
    CIM: ['SUPER LAVÁVEL'],
  },
  premium_acetinado: {
    SUV: ['TOQUE DE SEDA','TOQUE SEDA'], // aceita os dois
    SHW: ['METALATEX ELASTIC SEMIACETINADO'],
    CIM: ['DECORA SEDA'],
  },
  premium_semibrilho: {
    SUV: ['TOQUE BRILHO'],
    SHW: ['METALATEX ACRILICO SEMIBRILHO'],
    CIM: ['DECORA DIAMANTE'],
  },
};

// 6) escolhe pelo primeiro alvo que existir
function pickByPriority(sigla, cat, listaProdutos) {
  const arr = (regras[cat] || {})[sigla] || [];
  if (!arr.length) return null;

  for (const alvo of arr) {
    const A = up(alvo);
    const found = listaProdutos.find(p => up(p.acabamento) === A);
    if (found) return found;
  }
  return null;
}

const escolhido = pickByPriority(SIGLA, CAT, produtos);

// 7) monta só a mensagem
if (!escolhido) {
  return [{ json: { mensagem: `Não encontrei item premium compatível para a marca ${SIGLA} em ${SUPERF.toLowerCase() || 'parede interna'}. Quer tentar outro acabamento?` } }];
}

const volStr = volumeByEmbalagem(escolhido.embalagem) || escolhido.volume || VOLRAW || '';
const desc = `${escolhido.sigla} ${escolhido.cor} ${escolhido.acabamento} ${escolhido.embalagem} ${volStr}`.replace(/\s+/g,' ').trim();
const precoBRL = escolhido.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
const mensagem = `• ${desc} por ${precoBRL}\n\nPosso seguir com esse item?`;

return [{ json: { mensagem } }];

// Delay aleatório para dessincronizar
const delay = Math.random() * 2000;
await new Promise(resolve => setTimeout(resolve, delay));
return items;

// 🔥 CORREÇÃO: Pega dados do trigger original, não do Redis
const payload = $('Início: Receber Pedido do Cliente').first().json;

// 🔗 mapeamento fixo de marcas
const marcas = [
  { codigoEmpresa: '179', sigla: 'CIM', nome: 'CORAL' },
  { codigoEmpresa: '179', sigla: 'SHW', nome: 'SHERWIN WILLIAMS' },
  { codigoEmpresa: '179', sigla: 'SUV', nome: 'SUVINIL' },
];

// 📌 aliases de marcas (apelidos → nome oficial)
const aliases = {
  'tmc': 'sherwin williams',
  'tintas mc': 'sherwin williams',
  'sw': 'sherwin williams',
  'sherwin': 'sherwin williams',
  'sherwin-williams':'sherwin williams',
  'cim': 'coral',
  'suv': 'suvinil',
};

// 🔄 trata entrada de marca ou sigla
let marcaEntrada = (payload.Marca || '').toLowerCase().trim();
if (aliases[marcaEntrada]) {
  marcaEntrada = aliases[marcaEntrada];
}
const marca = marcas.find(m =>
  m.nome.toLowerCase() === marcaEntrada || m.sigla.toLowerCase() === marcaEntrada
);
if (!marca) throw new Error(`Marca '${payload.Marca}' não mapeada`);

// 🔤 normaliza cor → remove acentos e artigos/preposições iniciais
const normalizaCor = cor => {
  const stop = ['o ', 'a ', 'os ', 'as ', 'um ', 'uma ', 'de ', 'do ', 'da ', 'dos ', 'das '];
  let s = String(cor ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/\p{Diacritic}/gu, '')
    .trim();
  const w = stop.find(p => s.startsWith(p));
  if (w) s = s.slice(w.length).trim();
  return s;
};

// ==========================================================
// Aliases de categoria → premium | standard | economica
// ==========================================================
const norm = s => String(s || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/\p{Diacritic}/gu, '')
  .trim();

const categoriaAliases = {
  premium: [
    'premium', 'super premium', 'prime', 'top', 'topo', 'linha premium',
    'superior', 'gold', 'platina', 'platinum', 'diamante'
  ],
  standard: [
    'standard', 'standart', 'intermediaria', 'intermediario', 'intermediário',
    'intermediária', 'medio', 'médio', 'media', 'média', 'padrao', 'padrão',
    'tradicional', 'regular', 'comum', 'linha media', 'linha média'
  ],
  economica: [
    'economica', 'economico', 'econômica', 'econômico', 'economy',
    'entrada', 'basica', 'básica', 'popular', 'barata', 'mais barata',
    'essencial', 'value', 'promo', 'oferta', 'iniciante', 'starter'
  ],
};

function mapCategoria(catBruta) {
  const c = norm(catBruta);

  if (!c) return 'standard'; // default seguro

  // checa por prioridade: premium → standard → economica
  for (const alvo of categoriaAliases.premium)   if (c.includes(alvo))   return 'premium';
  for (const alvo of categoriaAliases.standard)  if (c.includes(alvo))   return 'standard';
  for (const alvo of categoriaAliases.economica) if (c.includes(alvo))   return 'economica';

  // heurísticas simples
  if (/(prem|top|superior)/.test(c)) return 'premium';
  if (/(inter|medio|m[eé]dio|padr[aã]o|trad)/.test(c)) return 'standard';
  if (/(econ|barat|b[aá]sic|popular|value|promo|oferta)/.test(c)) return 'economica';

  return 'standard';
}

// ==========================================================
// Função para converter KG para Litros (L)
// ==========================================================
const converteVolumeKgParaL = (volumeInput) => {
  if (!volumeInput) return '';

  const v = String(volumeInput).toLowerCase().replace(/\s+/g, '').replace(',', '.');

  if (v.includes('kg')) {
    if (v.startsWith('25') || v.startsWith('28')) {
      return '18L';
    }
    if (v.startsWith('3.6') || v.startsWith('5') || v.startsWith('5.6')) {
      return '3.6L';
    }
    if (v.startsWith('1.2') || v.startsWith('1.4') || v.startsWith('1.5')) {
      return '0.9L';
    }
  }

  return payload.Volume;
};

// Chama a nova função para tratar o volume
const volumeProcessado = converteVolumeKgParaL(payload.Volume);

// Normaliza categoria com aliases
const categoriaProcessada = mapCategoria(payload.categoria);

// monta objeto para o próximo HTTP
return [
  {
    json: {
      codigoEmpresa: marca.codigoEmpresa,
      sigla: marca.sigla,
      cor: normalizaCor(payload.Cor),
      volume: volumeProcessado,
      acabamento: payload.Acabamento,
      superficie: payload['superfície'] ?? payload.superficie ?? '',
      telefoneCliente: payload.telefoneCliente,
      categoria: categoriaProcessada,
    },
  },
];
